// Transform Gmail API output to the staging JSON schema
// expected by the Python triage engine.
// See n8n/README.md for full schema documentation.

const items = [];

for (const item of $input.all()) {
  const msg = item.json;

  // Extract headers into a lookup object
  const headers = {};
  for (const h of (msg.payload?.headers || [])) {
    headers[h.name.toLowerCase()] = h.value;
  }

  // Recursively extract plain text body from MIME parts
  function extractBody(payload) {
    if (payload.mimeType === 'text/plain' && payload.body?.data) {
      return Buffer.from(payload.body.data, 'base64').toString('utf-8');
    }
    for (const part of (payload.parts || [])) {
      const text = extractBody(part);
      if (text) return text;
    }
    return '';
  }

  // Collect attachment metadata (n8n has already saved them if using
  // a separate Download Attachments step — see README for details)
  const attachments = [];
  function collectAttachments(payload) {
    if (payload.filename && payload.body?.attachmentId) {
      attachments.push({
        filename: payload.filename,
        mime_type: payload.mimeType || 'application/octet-stream',
        attachment_id: payload.body.attachmentId,
        // local_path is filled in by the 'Save Attachments' step below.
        // Leave blank here; the Python script handles missing local_path gracefully.
        local_path: ''
      });
    }
    for (const part of (payload.parts || [])) {
      collectAttachments(part);
    }
  }
  collectAttachments(msg.payload || {});

  const email = {
    id: msg.id,
    thread_id: msg.threadId,
    subject: headers['subject'] || '(no subject)',
    from: headers['from'] || '',
    to: headers['to'] || '',
    date: headers['date'] || '',
    snippet: msg.snippet || '',
    body_text: extractBody(msg.payload || '').substring(0, 3000),
    labels: msg.labelIds || [],
    attachments: attachments
  };

  items.push({ json: email });
}

return items;
